package com.hospital.management.controller.billing;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/billing/payment/create")public class PaymentCreateServlet extends HttpServlet{private final PaymentService payments;private final BillService bills;public PaymentCreateServlet(){this(new PaymentServiceImpl(),new BillServiceImpl());}public PaymentCreateServlet(PaymentService p,BillService b){payments=p;bills=b;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=BillingRequest.id(q.getParameter("billId"));PaymentForm f=new PaymentForm();f.setBillId(id);show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PaymentForm f=BillingRequest.payment(q);ServiceResult<Long>x=payments.recordPayment(f,BillingRequest.audit(q),BillingRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/billing/view?id="+f.getBillId()+"&message=payment-recorded");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,PaymentForm f)throws ServletException,IOException{Bill b=f.getBillId()==null?null:bills.getBill(f.getBillId(),BillingRequest.user(q)).orElse(null);if(b==null){r.sendError(404);return;}q.setAttribute("bill",b);q.setAttribute("paymentForm",f);q.getRequestDispatcher("/WEB-INF/views/billing/payment-form.jsp").forward(q,r);}}
